import { NextResponse } from 'next/server';

export async function GET(request) {
  const { searchParams } = new URL(request.url);
  const zip = searchParams.get('zip');

  if (!zip || zip.length !== 5) {
    return NextResponse.json({ error: 'Invalid zip code' }, { status: 400 });
  }

  try {
    const response = await fetch(
      `https://nominatim.openstreetmap.org/search?postalcode=${zip}&country=US&format=json&addressdetails=1&limit=1`,
      {
        headers: {
          'User-Agent': 'PropIntel/1.0',
        },
      }
    );

    const data = await response.json();

    if (!data || data.length === 0) {
      return NextResponse.json({ error: 'Zip code not found' }, { status: 404 });
    }

    const result = data[0];
    const cityName = result.address.city || result.address.town || result.address.village || result.address.county || result.address.hamlet;
    const stateName = result.address.state;
    const stateCode = result.address['ISO3166-2-lvl4']?.split('-')[1] || result.address.state_code; // Nominatim state code can be tricky

    return NextResponse.json({
      city: cityName,
      state: stateName,
      stateCode: stateCode || '',
    });
  } catch (error) {
    console.error('Geocode error:', error);
    return NextResponse.json({ error: 'Failed to fetch location data' }, { status: 500 });
  }
}
